mapper.select:
SELECT _gid as mgr_no, cont_name, rec_date, job_type, rec_no, cont_type, work_name, start_sido, start_gu, start_dong, start_lotnum, start_lotsubnum, start_addr, start_lon, start_lat, exstart_date, end_sido, end_gu, end_dong, end_lotnum, end_lotsubnum, end_addr, end_lon, end_lat, exend_date, update_date FROM xeus.eocs_excavator
1=1
AND rec_no = #{recNo}
${sortCol} ${sortTyp}
(CASE WHEN start_lon IS NULL OR start_lat IS NULL THEN 0 ELSE 1 END), rec_date DESC
LIMIT ${limit} OFFSET ${offset}

SELECT _gid as mgr_no, cont_name, rec_date, job_type, rec_no, cont_type, work_name, start_sido, start_gu, start_dong, start_lotnum, start_lotsubnum, start_addr, start_lon, start_lat, exstart_date, end_sido, end_gu, end_dong, end_lotnum, end_lotsubnum, end_addr, end_lon, end_lat, exend_date, update_date
FROM xeus.eocs_excavator
rec_no = #{recNo}
